package ru.kryuch.krtg.searcher.controller;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.GetMapping;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RequestParam;import ru.kryuch.krtg.searcher.service.ChatService;@Controller@RequiredArgsConstructor@RequestMapping("/upload")public class UploadController {    private final ChatService chatService;    @GetMapping("/")    public String list(Model model) {        model.addAttribute("text", "");        model.addAttribute("page", "upload");        return "index";    }    @PostMapping("/")    public String add(@RequestParam("text") String text, Model model) {        if (text == null || text.trim().isEmpty()) {            model.addAttribute("error", "Текст не может быть пустым");            model.addAttribute("page", "upload");            return "index";        }        chatService.createNewContacts(text);        return "redirect:/upload/";    }}